I tried adding all the entries to the same compilation, but code duplication remains.

I will appreciate any hint/advice. Thanks in advance.

```javascript
    class MultiEntryPlugin {
        apply(compiler) {
          compiler.hooks.make.tapAsync(
            'MultiEntryPlugin',
            (compilation, callback) => {
              const outputOptions = {
                filename,
                chunkFilename: undefined,
                publicPath: compilation.outputOptions.publicPath,
                // HACK: globalObject is necessary to fix https://github.com/webpack/webpack/issues/6642
                globalObject: 'this',
              };

              const childCompiler = compilation.createChildCompiler(
                'monaco',
                outputOptions,
                [
                  new webpack.webworker.WebWorkerTemplatePlugin(),
                  new webpack.LoaderTargetPlugin('webworker'),
                ],
              );

              childCompiler.hooks.make.tapAsync(
                'MultiEntryPlugin',
                (compilation, callback) => {
                  Promise.all(
                    workers.map(({ entry }) => new Promise((resolve, reject) => {
                        compilation.addEntry(
                        childCompiler.context,
                        webpack.EntryPlugin.createDependency(
                          resolveMonacoPath(entry, monacoEditorPath),
                          { name: path.parse(entry).name },
                        ),
                        { name: path.parse(entry).name },
                        (err) => {
                          if (err) {
                            reject(err);
                          } else {
                            resolve();
                          }
                        },
                      );
                    })
                  )).finally(callback);
                },
              );

              childCompiler.runAsChild((err) => callback(err));
            },
          );
        }
      }
```

