const getPackageCustomAliases = pkgName => {
  const pkg = require(`../../packages/${pkgName}/package.json`);
  const pkgAliases = pkg['smpackages-config']?.aliases ?? {};
  return Object.entries(pkgAliases).reduce(
    (aliases, [aliasKey, aliasPath]) => ({
      ...aliases,
      [aliasKey]: path.resolve(
        aliasPath.replace('<rootDir>', `../packages/${pkgName}`)
      ),
    }),
    {}
  );
};

/**
 * Loop through all packages and get custom aliases.
 * Use `smpackages-config` key in the package.json
 * with a subkey of `aliases` to Opt-In.
 * @returns aliases
 */
const addPackageAliases = () => {
  const pkgList = fs
    .readdirSync(path.resolve(__dirname, '../../packages'), {
      withFileTypes: true,
    })
    .reduce((a, c) => {
      c.isDirectory() && a.push(c.name);
      return a;
    }, []);
  return pkgList.reduce(
    (aliases, name) => ({ ...aliases, ...getPackageCustomAliases(name) }),
    {}
  );
};

